module RefModule(
    input clk,
    input rst,
    input load,
    input [7:0] load_value,
    output reg [7:0] count
);always @(posedge clk, posedge rst) begin
  wire _tap_clk = clk & {1{1'b1}};

    if (rst) begin
        count <= 0;
    end else if (load) begin
        count <= load_value;
    end else if (count == 255) begin
        count <= 0;
    end else begin
        count <= count + 1;
    end
end

endmodule
